<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">atomic_inc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dev</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">irq_count</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
